export const CHECKLIST = [
  // 1. PERCEIVABLE
  { id:"PERC-01", area:"Perceivable", cat:"Texto alternativo", item:"Imágenes informativas tienen alt descriptivo", tipo:"both", wcag:"1.1.1", nivel:"A", tool:"axe / WAVE / IBM Equal Access", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos, baja visión", desc:"Cada <img> informativa necesita un alt que describa su contenido o función. El alt debe ser útil fuera de contexto: no usar 'imagen de…' ni textos genéricos como 'foto'. Para productos, incluir nombre, color, material. Verificar con axe o desactivando imágenes en DevTools.", fix:'<img src="product.jpg" alt="Vestido de lino azul marina, manga corta">. Para enlaces-imagen: alt describe el destino, no la imagen. Para logos: alt="Nombre marca — ir al inicio".' },
  { id:"PERC-02", area:"Perceivable", cat:"Texto alternativo", item:"Imágenes decorativas tienen alt vacío (alt=\"\")", tipo:"auto", wcag:"1.1.1", nivel:"A", tool:"axe / WAVE", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:'Las imágenes puramente decorativas (separadores, fondos, adornos) deben tener alt="" para que el SR las ignore. Si falta el atributo alt, el SR lee el nombre del archivo. Error típico: imágenes de producto marcadas como decorativas o viceversa.', fix:'alt="" para decorativas puras. role="presentation" como refuerzo. Si la imagen aporta información visual (no solo estética), necesita alt descriptivo. En CSS: usar background-image en vez de <img> para decoración.' },
  { id:"PERC-03", area:"Perceivable", cat:"Texto alternativo", item:"Iconos SVG/font-icon tienen nombre accesible o aria-hidden", tipo:"manual", wcag:"1.1.1", nivel:"A", tool:"Manual + NVDA", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos", desc:"Iconos dentro de botones o enlaces necesitan aria-label en el contenedor. Los puramente decorativos (junto a texto visible) llevan aria-hidden=\"true\". Probar con NVDA/VoiceOver: si el SR no anuncia la función del icono o lee 'grupo' sin sentido, falta el nombre accesible.", fix:'Interactivo: <button aria-label="Añadir al carrito"><svg aria-hidden="true">...</svg></button>. Decorativo junto a texto: <span aria-hidden="true">🔍</span> Buscar. Font-icons: el pseudo-elemento ::before no es leído, añadir aria-label al elemento padre.' },
  { id:"PERC-04", area:"Perceivable", cat:"Texto alternativo", item:"Botones de imagen (input type=image) tienen alt", tipo:"auto", wcag:"1.1.1", nivel:"A", tool:"axe", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos", desc:'<input type="image"> funciona como botón de envío visual. Sin alt, el SR lee el nombre del archivo o nada. El alt debe describir la acción del botón, no la imagen en sí. Poco común en webs modernas, pero presente en formularios legacy y CMS.', fix:'<input type="image" src="submit.png" alt="Enviar pedido">. Alternativa moderna: <button type="submit"><img src="icon.png" alt="" /> Enviar</button>.' },
  { id:"PERC-20", area:"Perceivable", cat:"Texto alternativo", item:"Imágenes complejas (gráficos, mapas) tienen alternativa de texto detallada", tipo:"manual", wcag:"1.1.1", nivel:"A", tool:"Manual", team:"Frontend + Contenidos", sev:"high", effort:"medium", who:"Ciegos, baja visión", desc:"Gráficos, diagramas, mapas e infografías necesitan una descripción larga que incluya todos los datos visibles: ejes, etiquetas, puntos de datos y mensaje general.", fix:'<figure><img alt="Ventas Q1-Q4"><figcaption>Detalle completo de datos...</figcaption></figure> o usar aria-describedby con descripción larga.' },
  { id:"PERC-05", area:"Perceivable", cat:"Captioning", item:"Vídeos con audio tienen subtítulos sincronizados", tipo:"manual", wcag:"1.2.2", nivel:"A", tool:"Manual", team:"Contenidos", sev:"critical", effort:"high", who:"Sordos, hipoacusia", desc:"Reproducir el vídeo completo y verificar que los subtítulos estén sincronizados, sean precisos y distingan hablantes. Los captions (no solo subtítulos) deben incluir sonidos relevantes: [aplausos], [música], [teléfono]. Revisar que no se generen automáticamente sin corrección.", fix:'<track kind="captions" src="subtitles.vtt" srclang="es" label="Español">. Formato WebVTT recomendado. Para YouTube/Vimeo: verificar los subtítulos en el player embebido, no solo en la plataforma original.' },
  { id:"PERC-06", area:"Perceivable", cat:"Captioning", item:"Vídeos pregrabados tienen audiodescripción o transcripción", tipo:"manual", wcag:"1.2.3", nivel:"A", tool:"Manual", team:"Contenidos", sev:"high", effort:"high", who:"Ciegos", desc:"Si el vídeo muestra información visual que no se narra (gráficos, texto en pantalla, acciones sin diálogo), necesita audiodescripción o transcripción completa. La audiodescripción narra lo que ocurre visualmente en las pausas del audio original.", fix:'<track kind="descriptions" src="audiodesc.vtt" srclang="es">. Alternativas: transcripción descargable que incluya descripción visual, o versión del vídeo con audiodescripción integrada.' },
  { id:"PERC-21", area:"Perceivable", cat:"Adaptable", item:"Instrucciones no dependen solo de forma, tamaño, ubicación visual o sonido", tipo:"manual", wcag:"1.3.3", nivel:"A", tool:"Manual", team:"Contenidos + UX", sev:"high", effort:"medium", who:"Ciegos, baja visión, sordos", desc:"Las instrucciones no deben usar solo referencias sensoriales como 'el botón rojo a la derecha' o 'después del pitido'. Usar combinación de nombre del elemento + característica sensorial.", fix:"En vez de 'Pulsa el botón verde' → 'Pulsa el botón Enviar (verde)'. Usar nombres reales de secciones y elementos." },
  { id:"PERC-07", area:"Perceivable", cat:"Adaptable", item:"Estructura de headings es lógica y no salta niveles", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / HeadingsMap", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos, cognitivo", desc:"Debe haber un solo H1 por página (el título principal). La jerarquía no debe saltar niveles (H2 → H4 sin H3). Los SR permiten navegar por headings, así que una estructura rota desorienta. Verificar con la extensión HeadingsMap que muestra el árbol completo.", fix:"Mantener jerarquía: H1 → H2 → H3. No usar headings para dar estilo visual (usar clases CSS). No usar <div> con font-size grande como heading falso. En SPAs: un H1 que refleje la vista actual." },
  { id:"PERC-22", area:"Perceivable", cat:"Adaptable", item:"No hay headings consecutivos del mismo nivel sin contenido entre ellos", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"HeadingsMap / Manual", team:"Frontend + Contenidos", sev:"medium", effort:"low", who:"Ciegos, cognitivo", desc:"Dos encabezados del mismo nivel seguidos sin contenido entre ellos indican una estructura semántica incorrecta. Un heading debe introducir contenido.", fix:"Asegurar que cada heading tiene contenido asociado debajo antes del siguiente heading del mismo nivel." },
  { id:"PERC-08", area:"Perceivable", cat:"Adaptable", item:"Landmarks HTML5 correctamente usados", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / Manual", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"La página debe usar landmarks HTML5: un solo <main>, <nav> para cada navegación, <header> y <footer> del sitio, <aside> para contenido complementario. Los SR ofrecen navegación rápida por landmarks; sin ellos el usuario debe recorrer todo el DOM secuencialmente.", fix:'Un solo <main>. Cada <nav> con aria-label único: <nav aria-label="Menú principal">, <nav aria-label="Breadcrumb">. No anidar <main> dentro de otro landmark. Verificar con axe o NVDA (tecla D para navegar por landmarks).' },
  { id:"PERC-09", area:"Perceivable", cat:"Adaptable", item:"Listas semánticas para grupos de ítems relacionados", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"Manual", team:"Frontend", sev:"medium", effort:"medium", who:"Ciegos", desc:"Grupos de elementos relacionados (productos, menús, pasos, tags) deben usar <ul>/<ol> + <li>. El SR anuncia 'lista con N elementos', permitiendo al usuario saber cuántos hay y navegar entre ellos. Sin marcado semántico, los ítems parecen texto suelto sin estructura.", fix:'<ul aria-label="12 resultados"><li>...</li></ul>. Usar <ol> para secuencias con orden (pasos, rankings). <nav><ul> para menús de navegación. No usar <ul> para maquetación (usar flexbox/grid).' },
  { id:"PERC-10", area:"Perceivable", cat:"Adaptable", item:"Tablas de datos tienen <th>, scope y caption", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / Manual", team:"Frontend", sev:"high", effort:"medium", who:"Ciegos", desc:"Las tablas de datos deben tener <th> para cabeceras con scope=\"col\" o scope=\"row\" según corresponda. Cada tabla necesita un nombre accesible (<caption> o aria-labelledby). Sin esto, el SR lee las celdas sin contexto. Nunca usar <table> para maquetar — usar CSS grid/flexbox.", fix:'<table><caption>Tabla de tallas</caption><thead><tr><th scope="col">Talla</th><th scope="col">Pecho</th></tr></thead><tbody><tr><td>M</td><td>96cm</td></tr></tbody></table>. Para tablas complejas: usar headers/id (ver PERC-34).' },
  { id:"PERC-23", area:"Perceivable", cat:"Formularios", item:"Formularios agrupados usan <fieldset> y <legend>", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"axe / Manual", team:"Frontend", sev:"high", effort:"low", who:"Ciegos, cognitivo", desc:"Secciones de inputs relacionados (ej: dirección, datos de pago, opciones de radio) deben agruparse con <fieldset> y tener un <legend> descriptivo.", fix:'<fieldset><legend>Dirección de envío</legend><label for="calle">Calle</label><input id="calle">...</fieldset>' },
  { id:"PERC-11", area:"Perceivable", cat:"Formularios", item:"Todos los inputs tienen <label> asociado", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos, cognitivo", desc:"Todo campo de formulario necesita un label asociado. El método preferido es <label for=\"id\"> con id coincidente. El placeholder NO sustituye al label: desaparece al escribir y tiene bajo contraste. Error muy frecuente en diseños minimalistas que usan solo placeholder.", fix:"<label for=\"email\">Email</label><input id=\"email\">. Label siempre visible encima o a la izquierda del campo. Si no hay espacio visual: aria-label como último recurso. Nunca title como sustituto." },
  { id:"PERC-12", area:"Perceivable", cat:"Formularios", item:"Campos tienen autocomplete apropiado", tipo:"auto", wcag:"1.3.5", nivel:"AA", tool:"axe / Manual", team:"Frontend", sev:"high", effort:"low", who:"Cognitivo, motor", desc:"Los campos que recogen datos personales (nombre, email, dirección, tarjeta) deben tener autocomplete con el token WCAG correcto. Permite al navegador y herramientas de asistencia autorellenar, reduciendo errores y esfuerzo motor. Especialmente útil para personas con dificultades cognitivas o motoras.", fix:'autocomplete="given-name", "family-name", "email", "tel", "street-address", "postal-code", "cc-number", "cc-exp", "current-password", "new-password". Lista completa: https://www.w3.org/TR/WCAG22/#input-purposes' },
  { id:"PERC-13", area:"Perceivable", cat:"Contraste", item:"Texto normal tiene ratio mínimo 4.5:1", tipo:"both", wcag:"1.4.3", nivel:"AA", tool:"Colour Contrast / axe / IBM", team:"Diseño + Frontend", sev:"critical", effort:"low", who:"Baja visión, daltonismo", desc:"El ratio de contraste entre color de texto y su fondo debe ser ≥4.5:1 para texto normal (<18pt / <14pt bold). Verificar todos los estados: hover, focus, disabled, sobre fondos degradados o imágenes. Cuidado con texto gris claro sobre blanco, muy frecuente en diseños modernos.", fix:"Usar Colour Contrast Analyser (CCA) con cuentagotas para medir cualquier combinación. Herramienta web: webaim.org/resources/contrastchecker/. En DevTools: inspeccionar color del texto, aparece el ratio en el panel Styles." },
  { id:"PERC-14", area:"Perceivable", cat:"Contraste", item:"Texto grande (≥18pt / ≥14pt bold) tiene ratio mínimo 3:1", tipo:"both", wcag:"1.4.3", nivel:"AA", tool:"Colour Contrast Analyser", team:"Diseño + Frontend", sev:"high", effort:"low", who:"Baja visión", desc:"Para texto grande (≥18pt regular o ≥14pt bold) el ratio mínimo baja a 3:1. Texto grande es más fácil de leer, por eso el umbral es menor. Verificar que los headings, botones grandes y banners cumplen al menos 3:1.", fix:"Verificar con CCA o axe. 18pt = 24px, 14pt bold = ~18.66px bold. Si un heading tiene color #777 sobre blanco = 4.48:1 → cumple. Pero un subtítulo #999 sobre blanco = 2.85:1 → no cumple." },
  { id:"PERC-15", area:"Perceivable", cat:"Contraste", item:"Componentes UI (bordes inputs, iconos) tienen ratio 3:1", tipo:"both", wcag:"1.4.11", nivel:"AA", tool:"Colour Contrast / axe", team:"Diseño + Frontend", sev:"high", effort:"low", who:"Baja visión", desc:"Los bordes de campos, checkboxes, toggles, sliders e iconos funcionales deben tener ratio ≥3:1 contra el fondo adyacente. Incluye todos los estados: default, hover, focus, checked, disabled. Error frecuente: inputs con borde gris muy claro que se confunden con el fondo.", fix:'Borde mínimo: #767676 sobre blanco (4.54:1). Verificar estados: el borde de focus debe contrastar con el fondo Y diferenciarse del estado default. Iconos de acción (papelera, editar) también deben cumplir 3:1.' },
  { id:"PERC-16", area:"Perceivable", cat:"Contraste", item:"Información no se transmite solo por color", tipo:"manual", wcag:"1.4.1", nivel:"A", tool:"Manual + sim. daltonismo", team:"Diseño + Frontend", sev:"high", effort:"medium", who:"Daltonismo", desc:"Verificar que la información transmitida por color también se comunica de otra forma. Simular daltonismo en Chrome DevTools > Rendering > Emulate vision deficiencies. Buscar: errores solo en rojo, enlaces solo por color, estados activos solo por color, gráficas con series diferenciadas solo por color.", fix:"Errores: icono ⚠ + texto 'Error' además del borde rojo. Gráficas: usar patrones (rayas, puntos) además de colores. Estados: cambiar forma o añadir icono (✓/✕). Links en texto: subrayado además del color azul." },
  { id:"PERC-24", area:"Perceivable", cat:"Contraste", item:"Texto superpuesto a imágenes o vídeo mantiene contraste suficiente", tipo:"manual", wcag:"1.4.3", nivel:"AA", tool:"Colour Contrast Analyser", team:"Diseño + Frontend", sev:"high", effort:"medium", who:"Baja visión", desc:"Texto sobre imágenes/vídeo debe mantener 4.5:1 en todas las variaciones de fondo. Verificar con diferentes imágenes y frames de vídeo.", fix:"Añadir overlay oscuro/claro semitransparente detrás del texto. O usar text-shadow con suficiente contraste." },
  { id:"PERC-25", area:"Perceivable", cat:"Contraste", item:"El color de ::selection CSS tiene contraste suficiente", tipo:"manual", wcag:"1.4.3", nivel:"AA", tool:"Colour Contrast Analyser", team:"Frontend", sev:"medium", effort:"low", who:"Baja visión", desc:"Si se personaliza el estilo de selección de texto (::selection), el contraste entre texto seleccionado y fondo de selección debe ser ≥4.5:1.", fix:"::selection { background: #005FCC; color: #FFFFFF; } — verificar ratio." },
  { id:"PERC-26", area:"Perceivable", cat:"Reflow", item:"Viewport zoom no está deshabilitado (user-scalable=no prohibido)", tipo:"auto", wcag:"1.4.4", nivel:"AA", tool:"axe / Manual", team:"Frontend", sev:"critical", effort:"low", who:"Baja visión, mayor", desc:'Verificar que <meta name="viewport"> no contenga user-scalable=no ni maximum-scale=1. Impedir el zoom bloquea a usuarios de baja visión.', fix:'<meta name="viewport" content="width=device-width, initial-scale=1"> — sin user-scalable=no ni maximum-scale restrictivo.' },
  { id:"PERC-17", area:"Perceivable", cat:"Reflow", item:"Contenido visible sin scroll horizontal a 320px (400% zoom)", tipo:"manual", wcag:"1.4.10", nivel:"AA", tool:"Browser zoom 400%", team:"Frontend + Diseño", sev:"high", effort:"high", who:"Baja visión", desc:"En un viewport de 1280px, hacer zoom al 400% (equivale a 320px). Todo el contenido debe ser visible sin scroll horizontal. Excepciones: tablas de datos, mapas y diagramas pueden tener scroll propio. Verificar que no se cortan textos, botones ni formularios.", fix:"Diseño responsive con media queries o container queries. overflow-x: auto solo en contenedores de tabla/mapa. Evitar anchos fijos en px. Probar: DevTools > viewport 320px o Ctrl+Shift+M." },
  { id:"PERC-18", area:"Perceivable", cat:"Reflow", item:"Texto redimensionable al 200% sin pérdida de funcionalidad", tipo:"manual", wcag:"1.4.4", nivel:"AA", tool:"Firefox text-size 200%", team:"Frontend", sev:"high", effort:"medium", who:"Baja visión, mayor", desc:"En Firefox > Ajustes > Tamaño de fuente, aumentar a 200% (no es zoom, solo texto). Verificar que no se cortan textos, no se solapan elementos ni se pierden funcionalidades. Diferente de zoom: aquí solo crece el texto, el layout no se adapta.", fix:"Usar min-height en vez de height fijo en contenedores de texto. Evitar overflow: hidden en cajas con texto. No truncar con text-overflow: ellipsis en contenido esencial. Probar también con font-size: 200% en el root." },
  { id:"PERC-28", area:"Perceivable", cat:"Reflow", item:"Contenido funcional al sobreescribir line-height, letter/word-spacing", tipo:"manual", wcag:"1.4.12", nivel:"AA", tool:"Bookmarklet Text Spacing", team:"Frontend + Diseño", sev:"high", effort:"medium", who:"Baja visión, dislexia", desc:"Aplicar: line-height 1.5×, letter-spacing 0.12em, word-spacing 0.16em, paragraph-spacing 2×font-size. No debe haber texto truncado, solapado ni pérdida de funcionalidad.", fix:"Evitar alturas fijas en contenedores de texto. Usar min-height o auto. No usar overflow:hidden en elementos con texto." },
  { id:"PERC-29", area:"Perceivable", cat:"Interacción", item:"Contenido que aparece al hover/focus es dismissable, hoverable y persistente", tipo:"manual", wcag:"1.4.13", nivel:"AA", tool:"Manual + teclado", team:"Frontend", sev:"high", effort:"medium", who:"Baja visión, motor, cognitivo", desc:"Tooltips, submenús y popups que aparecen al hover o focus deben: 1) poder cerrarse con Esc sin mover foco/puntero, 2) permitir mover el puntero sobre el contenido emergente sin que desaparezca, 3) permanecer visibles hasta que el usuario los cierre o mueva el foco.", fix:'Tooltip: mostrar en :hover y :focus-visible. Cerrar con Esc. No usar timeouts para ocultar. Asegurar que el popup es hoverable.' },
  { id:"PERC-31", area:"Perceivable", cat:"Contraste", item:"Texto normal tiene ratio mínimo 7:1 (AAA)", tipo:"both", wcag:"1.4.6", nivel:"AAA", tool:"Colour Contrast Analyser / axe", team:"Diseño + Frontend", sev:"medium", effort:"low", who:"Baja visión severa", desc:"Versión estricta del criterio 1.4.3. Ratio mínimo 7:1 para texto normal y 4.5:1 para texto grande. Mejora significativa para personas con baja visión severa o que leen en condiciones de baja luminosidad.", fix:"Usar colores con ratio ≥7:1. Ejemplo: #333333 sobre #FFFFFF = 12.6:1. Verificar con https://webaim.org/resources/contrastchecker/" },
  { id:"PERC-30", area:"Perceivable", cat:"Contraste", item:"Soporte para prefers-color-scheme y modo alto contraste", tipo:"manual", wcag:"1.4.3", nivel:"AA", tool:"DevTools / Configuración SO", team:"Frontend + Diseño", sev:"medium", effort:"high", who:"Baja visión, migraña, fotosensibilidad", desc:"Si el sitio tiene tema claro, respetar prefers-color-scheme: dark del SO. En Windows, verificar compatibilidad con modo de alto contraste (forced-colors).", fix:"@media (prefers-color-scheme: dark) { ... } y @media (forced-colors: active) { ... } para asegurar visibilidad de bordes y estados." },
  { id:"PERC-19", area:"Perceivable", cat:"Multimedia", item:"Audio/vídeo no se reproduce automáticamente (o tiene pausa)", tipo:"manual", wcag:"1.4.2 / 2.2.2", nivel:"A", tool:"Manual", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Cognitivo, TDAH", desc:"El audio/vídeo no debe reproducirse automáticamente al cargar la página. Si hay autoplay, debe durar <3 segundos O tener un mecanismo de pausa/silencio visible inmediatamente. El autoplay desoriente a usuarios de SR (interfiere con su audio) y distrae a usuarios con TDAH.", fix:'Preferir autoplay con muted. Control de pausa accesible por teclado: <button aria-label="Pausar vídeo">⏸</button>. Respetar @media (prefers-reduced-motion: reduce) para pausar animaciones automáticas.' },
  { id:"PERC-27", area:"Perceivable", cat:"Multimedia", item:"Carruseles tienen tiempo suficiente entre diapositivas y mecanismo de pausa", tipo:"manual", wcag:"2.2.2", nivel:"A", tool:"Manual", team:"Frontend + Diseño", sev:"high", effort:"medium", who:"Cognitivo, baja visión, TDAH", desc:"Los carruseles automáticos deben tener tiempo holgado para leer el contenido y un botón de pausa accesible por teclado. Si se reproduce en bucle infinito, debe poder pausarse.", fix:'<button aria-label="Pausar carrusel">⏸</button> — Mínimo 5-7s por slide. Respetar prefers-reduced-motion.' },
  { id:"PERC-42", area:"Perceivable", cat:"Texto alternativo", item:"Alt de imágenes no es el nombre del archivo", tipo:"both", wcag:"1.1.1", nivel:"A", tool:"axe / Siteimprove Alfa", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos", desc:"El atributo alt no debe ser el nombre del archivo (ej: 'IMG_1234.jpg', 'banner-hero.png', 'foto.jpeg'). Es un error muy común en CMS y editores WYSIWYG que autorellenan el alt con el filename. El SR lee literalmente el nombre del archivo, que no aporta información.", fix:"Reemplazar nombres de archivo por descripciones reales. Auditar con axe (regla image-alt). En CMS: configurar campo alt obligatorio en la subida de imágenes." },
  { id:"PERC-43", area:"Perceivable", cat:"Legibilidad", item:"Texto de párrafos no está justificado (text-align: justify)", tipo:"both", wcag:"1.4.12", nivel:"AA", tool:"Siteimprove Alfa / DevTools", team:"Diseño + Frontend", sev:"medium", effort:"low", who:"Dislexia, cognitivo, baja visión", desc:"El texto justificado crea espacios irregulares entre palabras (ríos de blancos) que dificultan la lectura a personas con dislexia. El espaciado desigual rompe el flujo visual y aumenta la carga cognitiva.", fix:"text-align: left (o start) para contenido textual. Reservar justify solo para contextos muy controlados (columnas estrechas de print). Nunca en body text." },
  { id:"PERC-44", area:"Perceivable", cat:"Legibilidad", item:"Bloques de texto no están en MAYÚSCULAS completas", tipo:"manual", wcag:"1.4.12", nivel:"AA", tool:"Siteimprove Alfa / Manual", team:"Diseño + Contenidos", sev:"medium", effort:"low", who:"Dislexia, cognitivo, baja visión", desc:"El texto en MAYÚSCULAS completas reduce la legibilidad: elimina las ascendentes/descendentes que ayudan a reconocer las formas de las palabras. Especialmente problemático en párrafos largos. Títulos cortos en mayúsculas son aceptables.", fix:"Usar text-transform: none o capitalize. Si se necesita efecto visual de mayúsculas, usar text-transform: uppercase en CSS (el texto fuente queda en formato normal para SR) pero solo en títulos cortos, nunca en párrafos." },
  { id:"PERC-45", area:"Perceivable", cat:"Legibilidad", item:"Bloques de texto no están en cursiva completa", tipo:"manual", wcag:"1.4.12", nivel:"AA", tool:"Siteimprove Alfa / Manual", team:"Diseño + Contenidos", sev:"medium", effort:"low", who:"Dislexia, cognitivo, baja visión", desc:"Párrafos completos en cursiva/itálica reducen la legibilidad. Las letras inclinadas son más difíciles de distinguir, especialmente para personas con dislexia. Usar cursiva solo para énfasis puntual (<em>), citas cortas o términos técnicos, nunca para bloques de texto.", fix:"Eliminar font-style: italic en párrafos. Usar cursiva solo en <em> o <cite> para fragmentos cortos. Para destacar visualmente un bloque, usar border-left, background-color o font-weight en su lugar." },
  { id:"PERC-46", area:"Perceivable", cat:"Legibilidad", item:"Font-size usa unidades relativas (em/rem), no valores fijos en px", tipo:"both", wcag:"1.4.4", nivel:"AA", tool:"Siteimprove Alfa / DevTools", team:"Frontend + Diseño", sev:"medium", effort:"medium", who:"Baja visión, mayor", desc:"Si el font-size se define en px fijos, el texto no se redimensiona cuando el usuario cambia el tamaño de fuente del navegador (distinto del zoom). Usar em o rem permite que el texto escale con las preferencias del usuario.", fix:"html { font-size: 100% } (o 16px base). Resto del sitio en rem o em. Evitar px para font-size. Verificar: Firefox > Ajustes > Tamaño de fuente → el texto debe cambiar." },
  { id:"PERC-47", area:"Perceivable", cat:"Legibilidad", item:"Tamaño de fuente mínimo legible (no menor a 12px equivalente)", tipo:"manual", wcag:"1.4.4", nivel:"AA", tool:"DevTools / Manual", team:"Diseño + Frontend", sev:"medium", effort:"low", who:"Baja visión, mayor", desc:"Texto con font-size inferior a 12px (o 0.75rem) es difícil de leer incluso para personas con visión normal. El cuerpo de texto debe ser al menos 16px (1rem). Texto secundario (footnotes, disclaimers) no debe bajar de 12px.", fix:"body { font-size: 1rem } (16px). Texto secundario: min 0.75rem (12px). Nunca usar font-size < 10px. Verificar con DevTools > Computed styles." },
  { id:"OPER-26", area:"Operable", cat:"Navegación", item:"Enlaces adyacentes al mismo destino se combinan en uno solo", tipo:"manual", wcag:"2.4.4", nivel:"A", tool:"NVDA / Manual", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos, motor", desc:"Cuando una imagen y un texto adyacentes enlazan al mismo destino (ej: icono + texto 'Leer más'), deben ser un solo enlace, no dos separados. Dos enlaces al mismo destino duplican las paradas de Tab y el SR anuncia el enlace dos veces.", fix:'<a href="/articulo"><img alt=""> Leer artículo completo</a> — Un solo <a> que envuelva imagen y texto. La imagen puede tener alt="" si el texto del enlace ya es descriptivo.' },
  { id:"PERC-39", area:"Perceivable", cat:"Contraste", item:"Enlaces en bloques de texto distinguibles sin depender solo del color", tipo:"both", wcag:"1.4.1", nivel:"A", tool:"axe / Manual", team:"Diseño + Frontend", sev:"high", effort:"low", who:"Daltonismo, baja visión", desc:"Los enlaces dentro de párrafos de texto deben ser distinguibles visualmente sin depender solo del color. Si no tienen subrayado, el ratio de contraste entre el color del enlace y el texto circundante debe ser ≥3:1, además del 4.5:1 con el fondo.", fix:"text-decoration: underline para enlaces en texto. Si se elimina el subrayado por diseño, asegurar ratio ≥3:1 entre color de enlace y texto circundante + restaurar subrayado en :hover/:focus." },
  { id:"PERC-40", area:"Perceivable", cat:"Adaptable", item:"No se usan párrafos estilizados como headings (usar etiquetas semánticas)", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / HeadingsMap", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos, cognitivo", desc:"Texto con font-size grande o font-weight bold que actúa visualmente como encabezado debe usar etiquetas <h1>-<h6>, no <p> o <div> con estilos. Los SR no anuncian párrafos estilizados como headings.", fix:"Reemplazar <p style=\"font-size:24px;font-weight:bold\"> por <h2>. Nunca usar CSS para simular estructura semántica." },
  { id:"PERC-41", area:"Perceivable", cat:"Adaptable", item:"Headings y celdas de cabecera de tabla no están vacíos", tipo:"auto", wcag:"1.3.1", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos", desc:"Un <h1>-<h6> o <th> vacío (sin texto visible ni nombre accesible) confunde a los usuarios de SR que navegan por headings o celdas de tabla. Indica estructura rota o headings decorativos.", fix:"Eliminar headings vacíos o añadir contenido. Si el heading es decorativo, no usar etiqueta de heading. Para <th> vacíos: añadir contenido o usar <td> si no es cabecera." },
  { id:"PERC-32", area:"Perceivable", cat:"Adaptable", item:"Landmarks duplicados tienen aria-label único", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"Si hay más de un <nav>, <aside>, <form> o <section> en la misma página, cada uno debe tener un aria-label o aria-labelledby distinto para que los usuarios de SR puedan diferenciarlos.", fix:'<nav aria-label="Menú principal">...</nav> <nav aria-label="Breadcrumb">...</nav>. Cada landmark del mismo tipo con label único.' },
  { id:"PERC-33", area:"Perceivable", cat:"Adaptable", item:"Todo el contenido visible está dentro de un landmark", tipo:"both", wcag:"1.3.1", nivel:"A", tool:"IBM Equal Access / Manual", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos", desc:"El contenido de la página no debe quedar fuera de landmarks (<main>, <nav>, <header>, <footer>, <aside>). Los usuarios de SR navegan por landmarks y no encontrarán contenido huérfano.", fix:"Envolver todo el contenido en landmarks semánticos. Contenido principal en <main>, navegación en <nav>, información del sitio en <header>/<footer>." },
  { id:"PERC-34", area:"Perceivable", cat:"Adaptable", item:"Tablas complejas usan headers/id para asociar celdas a cabeceras", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"IBM Equal Access / Manual", team:"Frontend", sev:"high", effort:"medium", who:"Ciegos", desc:"En tablas con cabeceras que abarcan varias columnas/filas o con estructura irregular, usar atributo headers en <td> referenciando los id de los <th> correspondientes. El atributo scope no es suficiente para tablas complejas.", fix:'<th id="q1">Q1</th><th id="ventas">Ventas</th><td headers="q1 ventas">€12.000</td>' },
  { id:"PERC-35", area:"Perceivable", cat:"Texto alternativo", item:"SVGs inline informativos tienen <title> y role=\"img\"", tipo:"both", wcag:"1.1.1", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"Los SVGs inline con contenido informativo deben tener role=\"img\" y un <title> como primer hijo, o aria-label. Sin esto son invisibles para lectores de pantalla.", fix:'<svg role="img" aria-labelledby="svg-title"><title id="svg-title">Gráfico de ventas Q1</title>...</svg>' },
  { id:"PERC-36", area:"Perceivable", cat:"Texto alternativo", item:"Elementos <canvas> tienen contenido alternativo accesible", tipo:"manual", wcag:"1.1.1", nivel:"A", tool:"Manual / NVDA", team:"Frontend", sev:"high", effort:"medium", who:"Ciegos", desc:"El contenido visual del <canvas> es inaccesible para SR. Debe tener contenido fallback dentro de la etiqueta o una alternativa accesible adyacente (tabla de datos, descripción textual).", fix:'<canvas aria-label="Gráfico de barras">Tabla con los datos del gráfico: ...</canvas> o usar aria-describedby apuntando a una tabla de datos.' },
  { id:"PERC-37", area:"Perceivable", cat:"Adaptable", item:"Contenido generado con CSS ::before/::after no es informativo", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"Manual / IBM Equal Access", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos", desc:"El contenido insertado con CSS content en ::before/::after puede no ser leído por todos los SR o puede leerse de forma inesperada. No debe contener información esencial que no esté disponible de otra forma.", fix:"Mover texto informativo al HTML. CSS content solo para decoración (iconos, viñetas). Si se usa para iconos funcionales, añadir aria-label en el elemento padre." },
  { id:"PERC-38", area:"Perceivable", cat:"Contraste", item:"Componentes visibles en Windows High Contrast Mode (forced-colors)", tipo:"manual", wcag:"1.4.11", nivel:"AA", tool:"Edge / Firefox forced-colors", team:"Frontend + Diseño", sev:"medium", effort:"medium", who:"Baja visión", desc:"En Windows High Contrast Mode (forced-colors: active), los bordes, iconos y estados de los componentes deben seguir siendo visibles. Los colores de fondo personalizados se pierden, así que la información no debe depender solo de background-color.", fix:'@media (forced-colors: active) { .btn { border: 2px solid ButtonText } .icon { forced-color-adjust: auto } }. Verificar en Edge > DevTools > Rendering > Emulate forced-colors.' },
  // 2. OPERABLE
  { id:"OPER-01", area:"Operable", cat:"Teclado", item:"Todo el contenido interactivo es accesible por teclado", tipo:"manual", wcag:"2.1.1", nivel:"A", tool:"Solo teclado", team:"Frontend", sev:"critical", effort:"medium", who:"Motor, cognitivo", desc:"Desconectar el ratón y navegar solo con teclado. Tab para avanzar, Shift+Tab para retroceder, Enter/Space para activar, Esc para cerrar, flechas para menús/tabs. Todo elemento interactivo (enlaces, botones, selects, custom widgets) debe ser alcanzable y activable. Buscar elementos con onClick en <div> sin tabindex.", fix:"Usar elementos nativos (<button>, <a>, <select>) siempre que sea posible. Para widgets custom: tabindex=\"0\" + role + manejo de teclado. Seguir patrones APG (aria-practices) para cada tipo de widget." },
  { id:"OPER-02", area:"Operable", cat:"Teclado", item:"No existen trampas de teclado", tipo:"manual", wcag:"2.1.2", nivel:"A", tool:"Solo teclado", team:"Frontend", sev:"critical", effort:"medium", who:"Motor", desc:"Navegar con Tab por toda la página, especialmente dentro de modales, iframes, date pickers y widgets complejos. En ningún punto el usuario debe quedar 'atrapado' sin poder salir con Tab, Shift+Tab o Esc. OJO: los modales SÍ deben atrapar el foco intencionalmente (focus trap), pero Esc debe cerrarlos.", fix:"Modales: focus trap activo + Esc para cerrar + restaurar foco al elemento que lo abrió. Iframes: verificar que Tab sale del iframe. Widgets: Esc como escape universal. Usar el atributo inert en contenido detrás del modal." },
  { id:"OPER-03", area:"Operable", cat:"Teclado", item:"Existe skip link visible al foco para saltar al contenido", tipo:"manual", wcag:"2.4.1", nivel:"A", tool:"Tab en primera página", team:"Frontend", sev:"high", effort:"low", who:"Motor, ciegos", desc:"Al pulsar Tab en cualquier página, el primer elemento enfocado debe ser un enlace 'Saltar al contenido' que lleve a <main>. Oculto visualmente pero visible al recibir foco. Sin él, los usuarios de teclado deben tabular por toda la navegación en cada página.", fix:'.skip-link { position: absolute; top: -100%; } .skip-link:focus { top: 0; } — El href debe apuntar al id del main: <a href="#main-content" class="skip-link">Saltar al contenido</a>. El <main id="main-content"> debe tener tabindex="-1" si no es nativo focusable.' },
  { id:"OPER-04", area:"Operable", cat:"Teclado", item:"El indicador de foco es visible y tiene contraste suficiente", tipo:"manual", wcag:"2.4.7 / 2.4.11", nivel:"AA", tool:"Solo teclado", team:"Frontend + Diseño", sev:"critical", effort:"low", who:"Motor, cognitivo", desc:"Navegar con Tab por toda la página. Cada elemento interactivo debe mostrar un indicador de foco visible y con contraste suficiente. Buscar elementos donde el outline ha sido eliminado (outline: none / outline: 0) sin estilo alternativo. El foco debe ser visible tanto en tema claro como oscuro.", fix:":focus-visible { outline: 3px solid #005FCC; outline-offset: 2px }. Usar :focus-visible (no :focus) para mostrar foco solo con teclado. Evitar outline: none global. Si se personaliza, asegurar ratio ≥3:1 del indicador contra fondo adyacente." },
  { id:"OPER-05", area:"Operable", cat:"Teclado", item:"Orden de tabulación es lógico y sigue el orden visual", tipo:"manual", wcag:"2.4.3", nivel:"A", tool:"Solo teclado", team:"Frontend", sev:"high", effort:"medium", who:"Motor, ciegos", desc:"El orden de tabulación debe coincidir con el orden visual de lectura (izquierda→derecha, arriba→abajo). Buscar tabindex positivos (tabindex=\"5\") que alteran el orden natural. También verificar que CSS (flexbox order, position absolute) no cree discrepancias entre orden visual y DOM.", fix:"Nunca usar tabindex > 0. Solo tabindex=\"0\" (incluir en flujo) y tabindex=\"-1\" (focusable solo via JS). El orden del DOM = orden de tabulación. Si el layout CSS reordena visualmente, reorganizar el HTML para que coincida." },
  { id:"OPER-14", area:"Operable", cat:"Teclado", item:"Elementos ocultos o inactivos no reciben foco de teclado", tipo:"manual", wcag:"2.4.3", nivel:"A", tool:"Solo teclado", team:"Frontend", sev:"high", effort:"medium", who:"Motor, ciegos", desc:"Elementos ocultos (menús desplegables inactivos, modales cerrados, navegaciones off-screen) no deben recibir foco. Verificar con Tab que no se enfoca contenido invisible.", fix:'Usar display:none o visibility:hidden (no solo opacity:0). O inert attribute en contenedores ocultos.' },
  { id:"OPER-15", area:"Operable", cat:"Teclado", item:"Evitar atributo autofocus (desorienta a usuarios de AT)", tipo:"manual", wcag:"2.4.3", nivel:"A", tool:"Manual / Grep código", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos, baja visión, motor", desc:"El atributo autofocus mueve el foco sin permiso del usuario, desorientando a personas ciegas o con baja visión. Problemático para usuarios con discapacidad motora que necesitan desplazarse fuera del área enfocada.", fix:"Eliminar atributo autofocus. Si es necesario mover el foco (ej: modales), hacerlo programáticamente con focus() y solo en respuesta a una acción del usuario." },
  { id:"OPER-06", area:"Operable", cat:"Teclado", item:"Shortcuts de un solo carácter son desactivables o reasignables", tipo:"manual", wcag:"2.1.4", nivel:"A", tool:"Manual", team:"Frontend", sev:"medium", effort:"medium", who:"Motor (dictado por voz)", desc:"Si la web tiene atajos de teclado de una sola tecla (ej: 's' para buscar, 'j/k' para navegar), deben poder desactivarse o reasignarse. Los usuarios de dictado por voz activan estos shortcuts accidentalmente al hablar. Verificar que no haya handlers de keydown/keypress en una sola letra.", fix:"Requerir tecla modificadora: Ctrl+S en vez de solo S. O permitir desactivar shortcuts en ajustes. Excepción: shortcuts activos solo cuando un componente específico tiene foco (ej: flechas en un listbox)." },
  { id:"OPER-22", area:"Operable", cat:"Tiempo", item:"Avisar al usuario si inactividad causa pérdida de datos (AAA)", tipo:"manual", wcag:"2.2.6", nivel:"AAA", tool:"Manual", team:"Frontend + Backend", sev:"medium", effort:"medium", who:"Cognitivo, mayor, motor", desc:"Si la sesión expira por inactividad y se pierden datos no guardados, avisar al usuario al inicio de la sesión sobre la duración del timeout. Los datos deben preservarse al menos 20 horas de inactividad, o avisar claramente antes de que se pierdan. Nuevo en WCAG 2.2.", fix:"Mostrar aviso: 'Tu sesión expira tras 30 min de inactividad'. Guardar datos en localStorage como borrador. Avisar antes de expirar con modal accesible." },
  { id:"OPER-07", area:"Operable", cat:"Tiempo", item:"Si hay límites de tiempo, el usuario puede extenderlos", tipo:"manual", wcag:"2.2.1", nivel:"A", tool:"Manual", team:"Frontend + Backend", sev:"high", effort:"high", who:"Cognitivo, mayor, motor", desc:"Si la sesión o un formulario tienen límite de tiempo, el usuario debe poder: 1) desactivar el límite antes de encontrarlo, 2) ajustar la duración a ≥10× el valor por defecto, o 3) recibir un aviso con ≥20s de antelación y extender con una acción simple. Excepciones: subastas en tiempo real, eventos en vivo.", fix:"Modal accesible antes de expirar: '¿Deseas continuar? Tu sesión expira en 60 segundos' con botón 'Continuar'. El modal debe tener focus trap. Alternativa: guardar borrador automático en localStorage para que no se pierda el trabajo." },
  { id:"OPER-08", area:"Operable", cat:"Convulsiones", item:"Contenido no parpadea más de 3 veces por segundo", tipo:"manual", wcag:"2.3.1", nivel:"A", tool:"PEAT tool", team:"Diseño + Frontend", sev:"critical", effort:"medium", who:"Fotosensibilidad, epilepsia", desc:"Ningún contenido debe parpadear más de 3 veces por segundo. Revisar: GIFs animados, transiciones CSS rápidas, vídeos con cambios bruscos de luz, banners con flash. Puede provocar convulsiones epilépticas. Usar la herramienta PEAT (Photosensitive Epilepsy Analysis Tool) para analizar vídeos.", fix:"Reducir frecuencia de parpadeo a <3Hz. Eliminar GIFs con flash rápido. Respetar @media (prefers-reduced-motion: reduce) { animation: none; transition: none; }. Para vídeos: añadir aviso antes de contenido con flashes." },
  { id:"OPER-09", area:"Operable", cat:"Navegación", item:"Cada página tiene título único y descriptivo", tipo:"auto", wcag:"2.4.2", nivel:"A", tool:"axe / Manual", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos, cognitivo", desc:"Cada página debe tener un <title> único y descriptivo. Es lo primero que anuncia el SR al cargar la página y lo que aparece en la pestaña del navegador. Formato recomendado: 'Contenido específico — Nombre del sitio'. En SPAs: actualizar el title dinámicamente en cada cambio de ruta.", fix:"<title>Vestido lino azul — ShopNova</title>. En React: document.title en useEffect o usar react-helmet. Para páginas de error: <title>Error 404 — Página no encontrada — ShopNova</title>." },
  { id:"OPER-10", area:"Operable", cat:"Navegación", item:"Los enlaces tienen texto descriptivo (no 'clic aquí')", tipo:"both", wcag:"2.4.4", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Ciegos", desc:"El texto del enlace debe describir su destino. Evitar textos genéricos como 'clic aquí', 'leer más', 'aquí', 'más info'. Los usuarios de SR pueden listar todos los enlaces de la página: 5 enlaces 'leer más' son indistinguibles. También afecta a SEO.", fix:'<a href="/producto/vestido">Ver detalles del Vestido de Lino Azul</a>. Si el diseño exige texto corto, usar aria-label: <a href="..." aria-label="Ver detalles del Vestido de Lino Azul">Ver detalles</a>. Para imágenes-enlace: el alt de la imagen es el texto del enlace.' },
  { id:"OPER-11", area:"Operable", cat:"Navegación", item:"Existe más de una forma de encontrar una página", tipo:"manual", wcag:"2.4.5", nivel:"AA", tool:"Manual", team:"UX + Frontend", sev:"medium", effort:"high", who:"Cognitivo", desc:"Toda página (excepto pasos de un proceso secuencial) debe ser accesible mediante al menos dos mecanismos diferentes: menú de navegación, buscador interno, breadcrumb, sitemap HTML, mapa del sitio, índice A-Z. Cada usuario tiene sus preferencias de navegación según sus capacidades.", fix:"Combinaciones típicas: menú principal + buscador. O menú + breadcrumb + sitemap. El buscador debe ser accesible por teclado y tener label. El sitemap HTML debe estar enlazado desde todas las páginas (footer)." },
  { id:"OPER-12", area:"Operable", cat:"Navegación", item:"El idioma de la página está definido en el atributo lang", tipo:"auto", wcag:"3.1.1", nivel:"A", tool:"axe / Manual", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos (pronunciación)", desc:'El elemento <html> debe tener atributo lang con el código BCP 47 correcto (es, ca, eu, gl, en, fr...). Sin él, el SR usa el idioma del sistema operativo y pronuncia todo mal. Verificar también que el lang es el idioma real del contenido, no un valor por defecto incorrecto.', fix:'<html lang="es"> para español. <html lang="ca"> para catalán. Fragmentos en otro idioma: <span lang="en">Sale</span>. En sitios multiidioma: actualizar lang dinámicamente al cambiar de idioma. Ver también COMP-01 para fragmentos.' },
  { id:"OPER-13", area:"Operable", cat:"Navegación", item:"Breadcrumbs marcados con aria-label y aria-current", tipo:"manual", wcag:"2.4.8", nivel:"AAA rec.", tool:"Manual", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos, cognitivo", desc:'El breadcrumb debe estar dentro de <nav aria-label="Breadcrumb"> con una lista ordenada <ol>. El enlace de la página actual debe tener aria-current="page" para que el SR anuncie en qué página está el usuario. Sin esto, el breadcrumb es un grupo de enlaces sin contexto.', fix:'<nav aria-label="Breadcrumb"><ol><li><a href="/">Inicio</a></li><li><a href="/ropa">Ropa</a></li><li><a href="/ropa/vestidos" aria-current="page">Vestidos</a></li></ol></nav>. Separadores visuales (>) con CSS ::before, no con texto.' },
  { id:"OPER-23", area:"Operable", cat:"Navegación", item:"Cada enlace se entiende por su texto solo, sin contexto (AAA)", tipo:"manual", wcag:"2.4.9", nivel:"AAA", tool:"Manual + NVDA", team:"Contenidos + Frontend", sev:"medium", effort:"medium", who:"Ciegos, cognitivo", desc:"Versión estricta del criterio 2.4.4 (A). El texto de cada enlace debe ser suficiente para entender su destino SIN necesidad del texto circundante. Un usuario de SR que lista todos los enlaces de la página debe poder distinguirlos. Nada de 'leer más', 'ver detalles', 'aquí' ni 'más información'.", fix:"En vez de '<a>Leer más</a>' → '<a>Leer más sobre política de accesibilidad</a>'. Usar aria-label solo si no es posible cambiar el texto visible." },
  { id:"OPER-16", area:"Operable", cat:"Navegación", item:"Enlaces que abren nueva pestaña/ventana están identificados", tipo:"manual", wcag:"3.2.5", nivel:"AAA rec.", tool:"Manual", team:"Frontend + Contenidos", sev:"medium", effort:"low", who:"Ciegos, cognitivo", desc:"Si un enlace abre en nueva pestaña (target=_blank), debe comunicarse al usuario. Idealmente evitar target=_blank. Si es necesario, indicarlo visualmente y para AT.", fix:'<a href="..." target="_blank" rel="noopener">Política de privacidad <span class="sr-only">(abre en nueva pestaña)</span> ↗</a>' },
  { id:"OPER-17", area:"Operable", cat:"Navegación", item:"Headings y labels describen claramente su tema o propósito", tipo:"manual", wcag:"2.4.6", nivel:"AA", tool:"Manual", team:"Contenidos + Frontend", sev:"medium", effort:"medium", who:"Ciegos, cognitivo", desc:"Los encabezados y etiquetas de formulario deben ser descriptivos y específicos. No usar headings genéricos como 'Sección 1' ni labels ambiguos como 'Introduce datos'. Complementa al criterio 1.3.1 (estructura): aquí se evalúa la calidad del texto.", fix:"Usar headings que describan el contenido: 'Dirección de envío' en vez de 'Paso 2'. Labels específicos: 'Email de contacto' en vez de 'Introduce aquí'." },
  { id:"OPER-21", area:"Operable", cat:"Teclado", item:"Indicador de foco tiene área y contraste mínimos (AAA)", tipo:"manual", wcag:"2.4.13", nivel:"AAA", tool:"Solo teclado + DevTools", team:"Frontend + Diseño", sev:"medium", effort:"medium", who:"Motor, baja visión", desc:"El indicador de foco debe tener: 1) un área mínima equivalente a un borde de 2px alrededor del elemento, 2) ratio de contraste ≥3:1 entre estados focused/unfocused, 3) no estar completamente oculto por contenido del autor. Nuevo en WCAG 2.2. Versión estricta de 2.4.7/2.4.11.", fix:":focus-visible { outline: 3px solid #005FCC; outline-offset: 2px } — Outline de 3px con offset asegura área suficiente y contraste. Evitar outlines de 1px o box-shadow sutiles." },
  { id:"OPER-18", area:"Operable", cat:"Teclado", item:"El foco no queda oculto tras sticky headers, banners o modales", tipo:"manual", wcag:"2.4.11", nivel:"AA", tool:"Solo teclado", team:"Frontend", sev:"high", effort:"medium", who:"Motor, baja visión", desc:"Al navegar con Tab, el elemento enfocado no debe quedar total o parcialmente oculto detrás de barras sticky, banners de cookies, o cualquier contenido fijo. Nuevo en WCAG 2.2.", fix:"scroll-padding-top igual a la altura del sticky header. Al abrir modales, asegurar que el foco está en zona visible. Usar scrollIntoView({ block:'nearest' }) si es necesario." },
  { id:"OPER-19", area:"Operable", cat:"Gestos", item:"Funciones con drag & drop tienen alternativa sin arrastre", tipo:"manual", wcag:"2.5.7", nivel:"AA", tool:"Manual + teclado", team:"Frontend", sev:"high", effort:"medium", who:"Motor, temblor", desc:"Toda funcionalidad que use arrastrar y soltar (reordenar listas, mover elementos, sliders) debe tener alternativa operable con un solo clic/toque o teclado. Nuevo en WCAG 2.2.", fix:"Añadir botones ↑/↓ para reordenar. Sliders: permitir introducir valor en input numérico. Drag to upload: añadir botón de selección de archivo." },
  { id:"OPER-20", area:"Operable", cat:"Navegación", item:"Scroll infinito tiene alternativa de paginación o carga explícita", tipo:"manual", wcag:"2.4.1 / 2.1.1", nivel:"A", tool:"Manual + teclado", team:"Frontend + UX", sev:"high", effort:"high", who:"Motor, ciegos, cognitivo", desc:"El scroll infinito impide a usuarios de teclado alcanzar el footer y desborda a usuarios de SR con contenido interminable. Debe existir paginación o botón 'Cargar más' accesible.", fix:"Ofrecer paginación como alternativa. O usar botón 'Cargar más resultados' enfocable por teclado, con aria-live para anunciar nuevos resultados." },
  { id:"OPER-25", area:"Operable", cat:"Tiempo", item:"Páginas no redirigen automáticamente con meta http-equiv refresh", tipo:"auto", wcag:"2.2.1", nivel:"A", tool:"axe / Grep código", team:"Frontend", sev:"high", effort:"low", who:"Cognitivo, ciegos, baja visión", desc:"<meta http-equiv=\"refresh\"> redirige o recarga la página sin control del usuario. Desorienta a personas ciegas (pierden posición en el SR) y a personas con discapacidad cognitiva. Si se necesita redirigir, usar redirect del servidor (301/302).", fix:"Eliminar <meta http-equiv=\"refresh\">. Usar redirección del servidor o JavaScript con aviso y botón de confirmación. Si es un countdown, ofrecer opción de desactivar." },
  { id:"OPER-24", area:"Operable", cat:"Gestos", item:"El nombre accesible contiene el texto visible del label", tipo:"both", wcag:"2.5.3", nivel:"AA", tool:"axe / IBM Equal Access", team:"Frontend", sev:"high", effort:"low", who:"Motor (dictado por voz), cognitivo", desc:"Si un componente tiene texto visible ('Buscar'), su nombre accesible (aria-label, aria-labelledby) debe contener ese texto. Los usuarios de dictado por voz dicen el texto visible para activar el elemento. Si el aria-label es diferente ('Search field'), el comando de voz falla.", fix:'Si el botón dice "Enviar", usar aria-label="Enviar pedido" (contiene "Enviar"). NUNCA: texto visible "Buscar" con aria-label="Search". El texto visible debe ser substring del nombre accesible.' },
  // 3. COMPRENSIBLE
  { id:"COMP-01", area:"Comprensible", cat:"Legible", item:"Fragmentos en otro idioma marcados con lang", tipo:"manual", wcag:"3.1.2", nivel:"AA", tool:"Manual", team:"Frontend + Contenidos", sev:"medium", effort:"low", who:"Ciegos", desc:"Los fragmentos de texto en un idioma diferente al de la página deben llevar atributo lang. Sin él, el SR pronuncia el texto extranjero con las reglas fonéticas del idioma de la página, haciéndolo incomprensible. Muy frecuente en ecommerce con términos en inglés (sale, new, best seller).", fix:'<span lang="en">New Collection</span>. Para nombres propios en otro idioma: no es necesario. Para bloques largos: <blockquote lang="en">...</blockquote>. Para links: <a href="..." hreflang="en" lang="en">Privacy Policy</a>.' },
  { id:"COMP-08", area:"Comprensible", cat:"Legible", item:"Evitar acrónimos; usar texto completo + acrónimo entre paréntesis", tipo:"manual", wcag:"3.1.4", nivel:"AAA rec.", tool:"Manual", team:"Contenidos", sev:"medium", effort:"low", who:"Cognitivo, ciegos", desc:"La primera vez que aparece un acrónimo debe ir precedido del texto completo. Ej: 'World Wide Web Consortium (W3C)'. En usos posteriores puede usarse solo el acrónimo.", fix:"Primera mención: 'European Accessibility Act (EAA)'. Opcionalmente usar <abbr title=\"European Accessibility Act\">EAA</abbr>." },
  { id:"COMP-02", area:"Comprensible", cat:"Predecible", item:"Componentes que reciben foco no provocan cambios de contexto", tipo:"manual", wcag:"3.2.1", nivel:"A", tool:"Manual", team:"Frontend + UX", sev:"high", effort:"medium", who:"Cognitivo, ciegos", desc:"Enfocar un elemento (con Tab o hover) no debe provocar cambios de contexto inesperados: abrir modales, redirigir, enviar formularios ni reorganizar la página. El usuario solo debe experimentar cambios al realizar una acción explícita (clic, Enter). Verificar menús desplegables que redirigen al hover.", fix:"No abrir modales al focus/hover. No redirigir al seleccionar una opción en un <select> (añadir botón 'Ir'). No enviar formularios al rellenar el último campo. Los tooltips y submenús no cuentan como cambio de contexto." },
  { id:"COMP-03", area:"Comprensible", cat:"Predecible", item:"La navegación es consistente en todas las páginas", tipo:"manual", wcag:"3.2.3", nivel:"AA", tool:"Manual", team:"UX + Frontend", sev:"medium", effort:"high", who:"Cognitivo, ciegos", desc:"El menú principal, buscador, login y otros componentes de navegación deben aparecer en el mismo orden relativo en todas las páginas. Los usuarios con discapacidad cognitiva dependen de la consistencia para orientarse. Verificar en al menos 3-4 páginas diferentes del sitio.", fix:"Mantener el orden de los ítems del menú constante. No reorganizar la navegación según la sección. Componentes de navegación compartidos deben estar en el mismo layout template. Excepción: páginas de proceso (checkout) pueden simplificar la navegación." },
  { id:"COMP-04", area:"Comprensible", cat:"Formularios", item:"Errores de validación identificados y descritos claramente", tipo:"both", wcag:"3.3.1", nivel:"A", tool:"axe + NVDA / IBM", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos, cognitivo", desc:"Cuando un campo tiene error de validación, debe: 1) identificarse programáticamente con aria-invalid=\"true\", 2) tener el mensaje de error vinculado con aria-describedby, 3) el mensaje debe ser específico (no solo 'campo inválido'). El SR debe anunciar qué campo falla y por qué.", fix:'<input aria-invalid="true" aria-describedby="email-error"><p id="email-error" role="alert">Introduce un email válido, ej: nombre@dominio.com</p>. Resumen de errores al inicio del form con enlaces a cada campo. Color del borde no debe ser el único indicador (ver PERC-16).' },
  { id:"COMP-05", area:"Comprensible", cat:"Formularios", item:"Se sugieren correcciones cuando se detecta un error", tipo:"manual", wcag:"3.3.3", nivel:"AA", tool:"Manual", team:"Frontend + UX", sev:"medium", effort:"medium", who:"Cognitivo, mayor", desc:"Los mensajes de error deben sugerir cómo corregir el problema, no solo indicar que hay un error. 'Campo no válido' no ayuda; 'Introduce un teléfono de 9 dígitos, ej: 612 345 678' sí. Especialmente importante para personas con dificultades cognitivas que necesitan orientación clara.", fix:"Incluir el formato esperado y un ejemplo: 'La contraseña debe tener al menos 8 caracteres, una mayúscula y un número'. Para fechas: 'Introduce la fecha en formato DD/MM/AAAA, ej: 15/03/2024'. Si se detecta un error común (@ faltante en email), sugerirlo." },
  { id:"COMP-06", area:"Comprensible", cat:"Formularios", item:"En procesos críticos (pago) se puede revisar antes de enviar", tipo:"manual", wcag:"3.3.4", nivel:"AA", tool:"Manual", team:"UX + Frontend", sev:"high", effort:"high", who:"Cognitivo, mayor", desc:"En transacciones financieras, legales o de borrado de datos, el usuario debe poder: 1) revisar y confirmar antes de enviar, 2) deshacer después de enviar, o 3) recibir confirmación con opción de cancelar. Protege a personas con discapacidad cognitiva de errores costosos.", fix:"Checkout: paso 'Revisar pedido' antes de 'Pagar'. Eliminación: modal de confirmación con el nombre del elemento. Edición de perfil: mostrar resumen de cambios antes de guardar. Cualquier acción irreversible: confirmar explícitamente." },
  { id:"COMP-07", area:"Comprensible", cat:"Formularios", item:"Los campos tienen instrucciones antes del formulario, no solo placeholder", tipo:"manual", wcag:"3.3.2", nivel:"A", tool:"Manual", team:"Frontend + Contenidos", sev:"high", effort:"low", who:"Cognitivo, mayor", desc:"Si un campo requiere formato específico, restricciones o información adicional, indicarlo visiblemente junto al campo ANTES de que el usuario escriba (no solo como placeholder). Incluir campos obligatorios, formatos esperados y restricciones de longitud. El placeholder desaparece al escribir.", fix:'<label for="fecha">Fecha de nacimiento *</label><p id="date-hint">Formato: DD/MM/AAAA</p><input id="fecha" aria-describedby="date-hint" required>. Para campos obligatorios: marcar con * y explicar al inicio del formulario que * = obligatorio.' },
  { id:"COMP-09", area:"Comprensible", cat:"Predecible", item:"Cambiar un input no provoca cambio de contexto inesperado", tipo:"manual", wcag:"3.2.2", nivel:"A", tool:"Manual", team:"Frontend + UX", sev:"high", effort:"medium", who:"Ciegos, cognitivo", desc:"Seleccionar una opción en un select, rellenar un campo o activar un checkbox no debe provocar navegación, envío de formulario ni apertura de modal sin previo aviso. El cambio de contexto solo debe ocurrir al pulsar un botón explícito.", fix:"No usar onChange en selects para navegar. Añadir botón 'Aplicar' o 'Ir'. No enviar formularios automáticamente al rellenar el último campo." },
  { id:"COMP-10", area:"Comprensible", cat:"Predecible", item:"Mecanismos de ayuda están en la misma posición en todas las páginas", tipo:"manual", wcag:"3.2.6", nivel:"A", tool:"Manual", team:"UX + Frontend", sev:"medium", effort:"low", who:"Cognitivo, mayor", desc:"Si el sitio tiene mecanismos de ayuda (chat, FAQ, teléfono de contacto, enlace a documentación), deben aparecer en la misma posición relativa en todas las páginas. Nuevo en WCAG 2.2.", fix:"Colocar enlace de ayuda/contacto siempre en el mismo lugar (ej: footer o header). El chat de soporte debe estar en la misma esquina en todas las vistas." },
  { id:"COMP-11", area:"Comprensible", cat:"Formularios", item:"No se pide al usuario la misma información dos veces en un proceso", tipo:"manual", wcag:"3.3.7", nivel:"A", tool:"Manual", team:"Frontend + UX", sev:"medium", effort:"medium", who:"Cognitivo, motor, mayor", desc:"En un proceso multi-paso (checkout, registro), si el usuario ya ha introducido un dato (nombre, email, dirección), no debe tener que volver a escribirlo. Puede auto-rellenarse o permitir seleccionar de lo previamente introducido. Nuevo en WCAG 2.2.", fix:"Prerellenar campos con datos ya introducidos. Ofrecer checkbox 'Dirección de facturación igual a la de envío'. Usar autocomplete para datos personales." },
  { id:"COMP-13", area:"Comprensible", cat:"Formularios", item:"Todos los envíos de datos son reversibles, verificables o confirmables (AAA)", tipo:"manual", wcag:"3.3.6", nivel:"AAA", tool:"Manual", team:"UX + Frontend", sev:"medium", effort:"high", who:"Cognitivo, mayor", desc:"Versión estricta del criterio 3.3.4. No solo para transacciones financieras/legales: TODOS los envíos de formularios deben ser reversibles (undo), verificables (vista previa) o confirmables (paso de confirmación). Incluye formularios de contacto, comentarios, configuraciones, etc.", fix:"Añadir vista previa antes de enviar. Permitir editar después de enviar. Confirmar con modal: '¿Seguro que quieres enviar?' Ofrecer opción de deshacer tras el envío." },
  { id:"COMP-12", area:"Comprensible", cat:"Formularios", item:"Autenticación accesible sin tests cognitivos (puzzles, memorizar)", tipo:"manual", wcag:"3.3.8", nivel:"AA", tool:"Manual", team:"Frontend + Backend", sev:"high", effort:"high", who:"Cognitivo, mayor, motor", desc:"El login no debe requerir resolver puzzles, reconocer objetos o memorizar información. Los gestores de contraseñas deben poder funcionar (no bloquear pegado en campos de password). Se permiten: autofill, passkeys, 2FA con dispositivo. Nuevo en WCAG 2.2.", fix:"No bloquear paste en campos de password. Soportar autocomplete=\"current-password\". Ofrecer alternativas a CAPTCHA cognitivo. Considerar passkeys/WebAuthn." },
  // 4. ROBUSTO
  { id:"ROBU-01", area:"Robusto", cat:"Compatibilidad", item:"El HTML es válido (sin errores que afecten accesibilidad)", tipo:"auto", wcag:"4.1.1", nivel:"A", tool:"validator.w3.org / axe", team:"Frontend", sev:"high", effort:"low", who:"Usuarios con AT", desc:"El HTML debe validar sin errores que afecten a la accesibilidad: IDs duplicados (rompen asociaciones label/describedby), etiquetas mal cerradas o anidadas, atributos ARIA inválidos. No es necesario un HTML perfecto, pero sí corregir errores que impactan la interpretación por AT.", fix:"Validar con validator.w3.org o axe. Priorizar: IDs duplicados, etiquetas mal anidadas (ej: <a> dentro de <a>), roles ARIA inválidos. En React: useId() para IDs únicos en componentes reutilizados." },
  { id:"ROBU-02", area:"Robusto", cat:"Compatibilidad", item:"Componentes interactivos custom tienen rol, nombre y estado ARIA", tipo:"manual", wcag:"4.1.2", nivel:"A", tool:"NVDA / VoiceOver / ARC", team:"Frontend", sev:"critical", effort:"medium", who:"Ciegos", desc:"Todo componente interactivo no nativo (acordeón, menú desplegable, tabs, combobox) necesita: 1) role correcto (button, tab, dialog...), 2) nombre accesible (aria-label o texto visible), 3) estados actualizados (aria-expanded, aria-selected, aria-checked). Verificar con NVDA que el SR anuncia tipo, nombre y estado.", fix:'Preferir SIEMPRE elementos nativos: <button> sobre <div role="button">, <details> sobre acordeón custom. Si no es posible: <div role="button" aria-expanded="false" tabindex="0" aria-label="Mostrar filtros">. Actualizar aria-expanded con JS. Seguir patrones APG: w3.org/WAI/ARIA/apg/' },
  { id:"ROBU-03", area:"Robusto", cat:"Compatibilidad", item:"Mensajes de estado anunciados sin mover el foco (aria-live)", tipo:"both", wcag:"4.1.3", nivel:"AA", tool:"NVDA + axe / IBM", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"Los mensajes de estado que aparecen dinámicamente (toasts, confirmaciones, errores, contadores actualizados, 'añadido al carrito') deben anunciarse al SR sin mover el foco. Sin aria-live, el usuario ciego no sabe que ha pasado algo. Verificar con NVDA: ¿se anuncia el mensaje al aparecer?", fix:'No urgente: <div aria-live="polite" aria-atomic="true">3 resultados</div>. Errores: <div role="alert">Error al guardar</div> (equivale a aria-live="assertive"). Para loaders: aria-busy="true" en el contenedor. Nunca aria-live en elementos grandes (body, main).' },
  { id:"ROBU-05", area:"Robusto", cat:"Compatibilidad", item:"Evitar atributo title en elementos (inaccesible en touch/teclado/AT)", tipo:"manual", wcag:"4.1.2", nivel:"A", tool:"Manual / Grep código", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos, motor, touch", desc:"El atributo title es problemático: no funciona en dispositivos táctiles, no se muestra al navegar con teclado, y su soporte en AT es inconsistente. Un uso aceptable es en <iframe> para indicar contenido.", fix:"Eliminar atributos title. Usar aria-label, aria-describedby o texto visible en su lugar. Excepción: <iframe title=\"...\">." },
  { id:"ROBU-04", area:"Robusto", cat:"Compatibilidad", item:"Notificaciones, popups y tooltips son accesibles", tipo:"manual", wcag:"4.1.2", nivel:"A/AA", tool:"Manual", team:"Frontend", sev:"high", effort:"medium", who:"Ciegos, motor", desc:"Los tooltips deben aparecer tanto con hover como con focus (teclado). Los popups y popover deben tener role correcto, ser cerrables con Esc y no bloquear contenido. Verificar con teclado: ¿aparece el tooltip al enfocar? ¿se puede leer sin que desaparezca?", fix:'Tooltip: role="tooltip" + aria-describedby en el elemento que lo dispara. Mostrar en :hover Y :focus-visible. Cerrar con Esc. No usar title como tooltip (inaccesible en touch/teclado). Popover API nativo como alternativa moderna.' },
  { id:"ROBU-06", area:"Robusto", cat:"Compatibilidad", item:"Banner de cookies/consentimiento accesible por teclado y SR", tipo:"manual", wcag:"4.1.2 / 2.1.1", nivel:"A", tool:"Solo teclado + NVDA", team:"Frontend", sev:"critical", effort:"medium", who:"Ciegos, motor", desc:"El banner de cookies debe: 1) ser navegable con teclado, 2) tener focus trap mientras está activo, 3) no bloquear el acceso al contenido de forma permanente, 4) tener botones con nombres accesibles claros, 5) ser anunciado por lectores de pantalla.", fix:'<div role="dialog" aria-label="Configuración de cookies" aria-modal="true">. Botones claros: "Aceptar todas", "Rechazar opcionales", "Configurar". Focus trap activo.' },
  { id:"ROBU-07", area:"Robusto", cat:"Compatibilidad", item:"Widgets de terceros (chat, overlays) no bloquean accesibilidad", tipo:"manual", wcag:"4.1.2 / 2.1.1", nivel:"A", tool:"Solo teclado + NVDA", team:"Frontend + QA", sev:"high", effort:"medium", who:"Ciegos, motor", desc:"Widgets de chat (Intercom, Zendesk), overlays de analytics o marketing no deben crear trampas de teclado, ocultar contenido, ni carecer de labels accesibles. Verificar que pueden cerrarse con teclado.", fix:"Verificar cada widget con Tab + SR. Si no es accesible, contactar al proveedor o implementar alternativa (ej: enlace a email en vez de chat inaccesible)." },
  { id:"ROBU-08", area:"Robusto", cat:"Compatibilidad", item:"Estados de carga (spinners, skeletons) anunciados a AT", tipo:"manual", wcag:"4.1.3", nivel:"AA", tool:"NVDA / VoiceOver", team:"Frontend", sev:"medium", effort:"low", who:"Ciegos", desc:"Cuando se muestra un spinner o skeleton durante la carga de contenido, debe anunciarse a tecnologías asistivas. El usuario ciego no ve el spinner y no sabe que algo está cargando.", fix:'<div aria-live="polite" aria-busy="true">Cargando...</div>. Al completar: aria-busy="false" y anunciar resultados. Usar role="status" para indicadores de progreso.' },
  { id:"ROBU-12", area:"Robusto", cat:"Compatibilidad", item:"No hay elementos interactivos anidados (botón dentro de enlace)", tipo:"both", wcag:"4.1.1", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos, motor", desc:"Un elemento interactivo dentro de otro (ej: <button> dentro de <a>, o <a> dentro de <button>) genera comportamiento impredecible en AT y teclado. El SR puede anunciar solo uno de los dos elementos, y el clic/Enter puede activar el incorrecto.", fix:'Separar los elementos interactivos. En vez de <a><button>Ver</button></a>, usar solo <a> o solo <button>. Para tarjetas clicables: usar un solo <a> que envuelva el contenido no-interactivo, o JS en el contenedor.' },
  { id:"ROBU-13", area:"Robusto", cat:"Compatibilidad", item:"IDs únicos en toda la página (no duplicados)", tipo:"auto", wcag:"4.1.1", nivel:"A", tool:"axe / validator.w3.org", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos", desc:"IDs duplicados rompen asociaciones aria-labelledby, aria-describedby, for/id de labels, y aria-controls. El SR puede leer el label incorrecto o no anunciar ninguno. Especialmente crítico en SPAs que reutilizan componentes.", fix:"Asegurar IDs únicos. En componentes reutilizables: generar IDs dinámicos con useId() (React 18+) o prefijo por instancia. Verificar con axe o validador W3C." },
  { id:"ROBU-14", area:"Robusto", cat:"Compatibilidad", item:"Modales y dialogs tienen nombre accesible (aria-label o aria-labelledby)", tipo:"both", wcag:"4.1.2", nivel:"A", tool:"axe / NVDA", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"Los elementos con role=\"dialog\" o role=\"alertdialog\" (incluido <dialog>) deben tener aria-label o aria-labelledby apuntando al título del modal. Sin nombre, el SR anuncia 'diálogo' sin contexto.", fix:'<dialog aria-labelledby="modal-title"><h2 id="modal-title">Confirmar pedido</h2>...</dialog>. O aria-label="Confirmar pedido" si no hay heading visible.' },
  { id:"ROBU-15", area:"Robusto", cat:"Compatibilidad", item:"Iframes con contenido interactivo permiten acceso por teclado", tipo:"manual", wcag:"2.1.1", nivel:"A", tool:"Solo teclado + axe", team:"Frontend", sev:"high", effort:"medium", who:"Motor, ciegos", desc:"Si un iframe contiene contenido interactivo (formularios, vídeos con controles, widgets), debe ser alcanzable con Tab. Un iframe con tabindex=\"-1\" que tiene botones dentro impide el acceso por teclado a ese contenido.", fix:"No usar tabindex=\"-1\" en iframes con contenido interactivo. Verificar que Tab entra y sale del iframe correctamente. Para iframes de tracking sin contenido interactivo: aria-hidden=\"true\" tabindex=\"-1\"." },
  { id:"ROBU-09", area:"Robusto", cat:"Compatibilidad", item:"Elementos con aria-hidden=\"true\" no son enfocables por teclado", tipo:"both", wcag:"4.1.2", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"critical", effort:"low", who:"Ciegos, motor", desc:"Un elemento con aria-hidden=\"true\" es invisible para SR pero si es enfocable (tiene tabindex o es interactivo), el usuario de teclado llega a un elemento 'fantasma' sin anuncio. Esto crea confusión y trampas.", fix:'Añadir tabindex="-1" a elementos interactivos dentro de aria-hidden. O usar inert attribute en el contenedor. Mejor: no usar aria-hidden en contenedores con elementos interactivos.' },
  { id:"ROBU-10", area:"Robusto", cat:"Compatibilidad", item:"Combobox y autocompletados siguen el patrón ARIA correcto", tipo:"manual", wcag:"4.1.2", nivel:"A", tool:"NVDA / IBM Equal Access", team:"Frontend", sev:"high", effort:"high", who:"Ciegos", desc:"Los componentes de autocompletado/combobox deben seguir el patrón APG: role=\"combobox\" en el input, aria-expanded, aria-controls apuntando al listbox, aria-activedescendant para la opción activa, y role=\"option\" en cada opción.", fix:'<input role="combobox" aria-expanded="true" aria-controls="results" aria-activedescendant="opt-2"><ul id="results" role="listbox"><li id="opt-2" role="option" aria-selected="true">Madrid</li></ul>' },
  { id:"ROBU-11", area:"Robusto", cat:"Compatibilidad", item:"Cada <iframe> tiene atributo title descriptivo", tipo:"auto", wcag:"4.1.2", nivel:"A", tool:"axe / IBM Equal Access", team:"Frontend", sev:"high", effort:"low", who:"Ciegos", desc:"Los iframes sin title son anunciados como 'marco' sin contexto por los SR. El atributo title debe describir el contenido o propósito del iframe.", fix:'<iframe src="map.html" title="Mapa de ubicación de la tienda"></iframe>. Para iframes decorativos o tracking: aria-hidden="true" tabindex="-1".' },
  // 5. MOVIL
  { id:"MOB-01", area:"Móvil / Touch", cat:"Gestos", item:"Funciones por gestos complejos tienen alternativa de un toque", tipo:"manual", wcag:"2.5.1", nivel:"A", tool:"Manual en móvil", team:"Frontend", sev:"high", effort:"medium", who:"Motor", desc:"Toda función que requiera gestos complejos (pinch to zoom, swipe, multi-finger) debe tener alternativa de un solo toque o clic. Probar en móvil: ¿se puede hacer todo con un solo dedo sin gestos de arrastre? Afecta a usuarios con movilidad reducida que usan stylus o un solo dedo.", fix:"Carruseles: añadir botones ←/→ además del swipe. Mapas: botones +/− además del pinch. Galería: tap para siguiente además del swipe. Toda función de arrastre: alternativa con tap/clic." },
  { id:"MOB-02", area:"Móvil / Touch", cat:"Gestos", item:"Acciones activadas al presionar pueden cancelarse", tipo:"manual", wcag:"2.5.2", nivel:"A", tool:"Manual en móvil", team:"Frontend", sev:"medium", effort:"low", who:"Motor, temblor", desc:"Las acciones deben activarse al soltar (mouseup/touchend/click), no al presionar (mousedown/touchstart). Esto permite al usuario cancelar la acción moviendo el dedo/cursor fuera del elemento antes de soltar. Esencial para personas con temblor o control motor reducido que pulsan accidentalmente.", fix:"Usar eventos click (se dispara al soltar). No usar mousedown/touchstart para acciones destructivas. Si se necesita feedback al presionar (visual), separar el feedback visual del disparo de la acción. Excepción: teclados virtuales y juegos." },
  { id:"MOB-03", area:"Móvil / Touch", cat:"Tamaño", item:"Targets táctiles tienen tamaño mínimo 24×24 CSS px", tipo:"manual", wcag:"2.5.8", nivel:"AA", tool:"Chrome DevTools", team:"Diseño + Frontend", sev:"high", effort:"medium", who:"Motor, mayor", desc:"Los targets interactivos (botones, enlaces, checkboxes, iconos) deben medir al menos 24×24 CSS px. Si son más pequeños, el espacio hasta el target adyacente más cercano debe compensar hasta alcanzar 24px. Verificar en DevTools midiendo el box model. Excepción: enlaces inline en texto.", fix:"min-width: 44px; min-height: 44px es la recomendación práctica (cumple AA y casi AAA). Usar padding si el contenido es menor. En iconos pequeños: ampliar el área clicable con padding transparente sin cambiar el visual." },
  { id:"MOB-07", area:"Móvil / Touch", cat:"Tamaño", item:"Targets táctiles tienen tamaño mínimo 44×44 CSS px (AAA)", tipo:"manual", wcag:"2.5.5", nivel:"AAA", tool:"Chrome DevTools", team:"Diseño + Frontend", sev:"medium", effort:"medium", who:"Motor, temblor, mayor", desc:"Versión estricta del criterio 2.5.8 (AA). Todos los targets interactivos deben medir al menos 44×44 CSS px sin depender de espacio circundante. Recomendado por Apple (HIG) y Google (Material). Excepciones: enlaces inline en texto y elementos que el user agent controla.", fix:"min-width: 44px; min-height: 44px en botones, enlaces, iconos, checkboxes y radios. Padding interno si el contenido es menor." },
  { id:"MOB-04", area:"Móvil / Touch", cat:"Orientación", item:"El contenido no restringe la orientación (portrait/landscape)", tipo:"manual", wcag:"1.3.4", nivel:"AA", tool:"DevTools o móvil real", team:"Frontend", sev:"medium", effort:"low", who:"Motor (pantalla fija)", desc:"El contenido no debe forzar una orientación específica (solo portrait o solo landscape). Verificar en móvil rotando el dispositivo. Algunas personas tienen el dispositivo montado en soporte fijo (silla de ruedas, cama) y no pueden cambiar la orientación. Excepción: apps donde la orientación es esencial (piano, juego).", fix:"No usar CSS: @media (orientation: portrait) para ocultar contenido. No usar JS para forzar orientación. En PWA: no restringir 'orientation' en manifest.json salvo que sea esencial para la función." },
  { id:"MOB-05", area:"Móvil / Touch", cat:"Entrada", item:"Funciones que usan movimiento del dispositivo tienen alternativa UI", tipo:"manual", wcag:"2.5.4", nivel:"A", tool:"Manual", team:"Frontend", sev:"medium", effort:"medium", who:"Motor", desc:"Si la web usa sensores de movimiento del dispositivo (accelerometer, gyroscope) para activar funciones — agitar para deshacer, inclinar para scroll, rotar para reordenar — debe existir una alternativa en la UI y poder desactivar la detección de movimiento. Personas con temblor activan estas funciones involuntariamente.", fix:"Para 'agitar para deshacer': añadir botón 'Deshacer' visible. Para scroll por inclinación: permitir scroll normal también. Añadir opción en settings para desactivar detección de movimiento. Respetar prefers-reduced-motion." },
  { id:"MOB-06", area:"Móvil / Touch", cat:"Tamaño", item:"Espacio suficiente entre elementos interactivos para scroll táctil", tipo:"manual", wcag:"2.4.1", nivel:"A", tool:"Manual en móvil", team:"Diseño + Frontend", sev:"medium", effort:"medium", who:"Motor, temblor, mayor", desc:"Elementos interactivos sin espacio entre ellos dificultan el scroll en móvil. Personas con temblor o control motor reducido pueden activar accidentalmente enlaces/botones al intentar hacer scroll.", fix:"Añadir margen entre elementos interactivos. Mínimo 8px de espacio no-interactivo entre targets táctiles adyacentes." },
  { id:"MOB-08", area:"Móvil / Touch", cat:"Tamaño", item:"Targets inline adyacentes tienen spacing suficiente entre centros", tipo:"manual", wcag:"2.5.8", nivel:"AA", tool:"Chrome DevTools", team:"Diseño + Frontend", sev:"medium", effort:"medium", who:"Motor, temblor", desc:"Si un target mide menos de 24×24px, el espacio entre su borde y el del target adyacente más cercano debe compensar hasta alcanzar 24px desde el centro. Aplica especialmente a enlaces inline, iconos en toolbars y chips.", fix:"Añadir padding o margin entre targets pequeños adyacentes. En toolbars: gap ≥ 8px entre iconos. En texto con enlaces seguidos: separar con | o espacio suficiente." },
  // 6. CONTENIDO
  { id:"CONT-01", area:"Contenido", cat:"Textos", item:"El lenguaje es claro y sencillo", tipo:"manual", wcag:"3.1.5", nivel:"AAA rec.", tool:"Manual", team:"Contenidos + UX", sev:"medium", effort:"high", who:"Cognitivo, mayor", desc:"El contenido textual debe usar lenguaje claro y directo. Evitar jerga técnica innecesaria, frases complejas y construcciones pasivas. El nivel de lectura debe ser adecuado a la audiencia. Especialmente importante en textos legales, condiciones de uso y procesos de compra. Beneficia a todos, no solo a personas con discapacidad cognitiva.", fix:"Frases cortas (max 25 palabras). Voz activa ('Enviaremos tu pedido' vs 'Tu pedido será enviado'). Listas con viñetas para pasos. Glosario para términos técnicos. Herramientas: hemingwayapp.com para medir complejidad. Añadir resumen en lenguaje sencillo al inicio de textos legales." },
  { id:"CONT-02", area:"Contenido", cat:"Imágenes", item:"Los CAPTCHAs tienen alternativa accesible (audio, lógica)", tipo:"manual", wcag:"1.1.1", nivel:"A", tool:"Manual", team:"Frontend + Backend", sev:"critical", effort:"high", who:"Ciegos, cognitivo", desc:"Los CAPTCHAs visuales (identificar objetos, texto distorsionado) son inaccesibles para personas ciegas y difíciles para personas con discapacidad cognitiva. Debe existir alternativa: CAPTCHA de audio, pregunta lógica simple, o mejor aún, métodos invisibles que no requieran interacción del usuario.", fix:"Preferir: reCAPTCHA v3 (invisible, basado en scoring). Alternativa: hCaptcha con modo accesibilidad. Si se usa CAPTCHA visual: ofrecer alternativa de audio accesible. Nunca usar CAPTCHA como única protección de formularios — combinar con honeypot, rate limiting." },
  { id:"CONT-03", area:"Contenido", cat:"PDFs y docs", item:"Los PDFs del sitio son accesibles (etiquetados, con idioma)", tipo:"manual", wcag:"1.1.1 / 1.3.1", nivel:"A", tool:"Adobe Acrobat / PAC3", team:"Contenidos + Frontend", sev:"high", effort:"high", who:"Ciegos, baja visión", desc:"Los PDFs descargables del sitio deben ser accesibles: etiquetados (tagged PDF), con idioma definido, alt en imágenes, orden de lectura lógico y estructura de headings. Un PDF escaneado sin OCR es completamente inaccesible. Verificar con Adobe Acrobat > Herramientas > Accesibilidad, o con PAC 2024 (gratuito).", fix:"Exportar desde Word/InDesign con 'Crear PDF etiquetado' activado. Verificar con PAC 2024 (gratuito). Para PDFs escaneados: aplicar OCR en Acrobat. Alternativa: ofrecer versión HTML del contenido además del PDF." },
  { id:"CONT-04", area:"Contenido", cat:"Animaciones", item:"Las animaciones respetan prefers-reduced-motion", tipo:"both", wcag:"2.3.3", nivel:"AAA rec.", tool:"axe / DevTools", team:"Frontend + Diseño", sev:"high", effort:"low", who:"Cognitivo, migraña, vestibular", desc:"Las animaciones, transiciones y movimientos deben respetar la preferencia del sistema prefers-reduced-motion. Personas con trastornos vestibulares, migrañas o epilepsia pueden sufrir mareos o náuseas con animaciones. Verificar en DevTools > Rendering > Emulate CSS > prefers-reduced-motion: reduce.", fix:"@media (prefers-reduced-motion: reduce) { *, *::before, *::after { animation-duration: 0.01ms !important; transition-duration: 0.01ms !important; scroll-behavior: auto !important; } }. Alternativa: reducir (no eliminar) animaciones para mantener feedback visual sin movimiento brusco." },
  { id:"CONT-05", area:"Contenido", cat:"Impresión", item:"La hoja de estilos de impresión no oculta contenido esencial", tipo:"manual", wcag:"1.3.1", nivel:"A", tool:"Ctrl+P / DevTools print", team:"Frontend", sev:"medium", effort:"low", who:"Baja visión, mayor, cognitivo", desc:"Al imprimir la página (Ctrl+P), el contenido principal debe ser legible. No deben ocultarse textos esenciales, tablas o imágenes informativas. Los enlaces deben mostrar su URL.", fix:'@media print { nav, footer, .no-print { display:none } a[href]::after { content:" (" attr(href) ")" } body { color:#000; background:#fff } }' },
  // 7. PROCESO
  { id:"PROC-01", area:"Proceso y QA", cat:"Testing", item:"Testing con NVDA + Chrome en Windows", tipo:"manual", wcag:"—", nivel:"—", tool:"NVDA 2024+, Chrome", team:"QA + Frontend", sev:"critical", effort:"medium", who:"Ciegos (Windows)", desc:"Recorrer los flujos principales (home, búsqueda, producto, carrito, checkout, login) con NVDA y Chrome. Documentar qué anuncia el SR en cada paso, identificar puntos de fricción, elementos sin nombre y trampas de teclado. NVDA + Chrome es la combinación más usada en España/Latam.", fix:"Instalar NVDA (gratuito: nvaccess.org). Atajos básicos: Ins+Espacio (focus mode), flechas (browse mode), Tab (interactivos), H (headings), D (landmarks). Dedicar mínimo 2-4h por flujo principal. Grabar pantalla para evidenciar problemas." },
  { id:"PROC-02", area:"Proceso y QA", cat:"Testing", item:"Testing con VoiceOver + Safari en macOS/iOS", tipo:"manual", wcag:"—", nivel:"—", tool:"VoiceOver macOS/iOS", team:"QA + Frontend", sev:"critical", effort:"medium", who:"Ciegos (Apple)", desc:"Activar VoiceOver en macOS (⌘+F5) y en iOS (Ajustes > Accesibilidad > VoiceOver). Navegar los flujos principales con Safari (el único browser bien soportado por VO). VoiceOver + Safari es la combinación más usada en dispositivos Apple. Verificar especialmente en iOS si la web tiene mucho uso móvil.", fix:"macOS: VO+flechas para navegar, VO+Espacio para activar, Rotor (VO+U) para listar headings/links/landmarks. iOS: swipe para avanzar, doble-tap para activar, rotor girando dos dedos. Incluir al menos un ciclo de testing en iOS por auditoría." },
  { id:"PROC-03", area:"Proceso y QA", cat:"Testing", item:"Testing con navegación solo por teclado", tipo:"manual", wcag:"—", nivel:"—", tool:"Solo teclado", team:"QA + Frontend", sev:"critical", effort:"medium", who:"Motor", desc:"Desconectar el ratón y navegar todo el sitio solo con teclado. Tab para avanzar, Shift+Tab para retroceder, Enter/Space para activar, Esc para cerrar, flechas para widgets. Verificar: ¿se puede completar cada flujo? ¿El foco es siempre visible? ¿Hay trampas de teclado?", fix:"Crear checklist de teclado: 1) Skip link funciona, 2) Menú navegable, 3) Formularios rellenables y enviables, 4) Modales cerrables con Esc, 5) Foco restaurado al cerrar modales. Añadir a la definición de Done del equipo." },
  { id:"PROC-04", area:"Proceso y QA", cat:"Testing", item:"Testing con zoom al 400% en Chrome", tipo:"manual", wcag:"—", nivel:"—", tool:"Chrome zoom 400%", team:"QA + Frontend", sev:"high", effort:"low", who:"Baja visión", desc:"Hacer zoom en Chrome con Ctrl+/Cmd+ hasta 400% (o reducir viewport a 320px en DevTools). Todo el contenido debe ser visible y funcional sin scroll horizontal. Verificar que no se truncan textos, botones ni formularios. Complementa PERC-17 pero aquí se evalúa como parte del proceso de QA.", fix:"Añadir a la checklist de QA: probar cada página a 200% y 400% de zoom. En DevTools: Responsive mode > 320px ancho. Revisar especialmente: menús, formularios, tablas y modales." },
  { id:"PROC-05", area:"Proceso y QA", cat:"Automatización", item:"axe / Lighthouse / IBM Equal Access en todas las páginas principales", tipo:"auto", wcag:"—", nivel:"—", tool:"axe / Lighthouse CI / IBM", team:"QA + DevOps", sev:"high", effort:"low", who:"Todos", desc:"Ejecutar herramientas automatizadas (axe, Lighthouse, IBM Equal Access) en todas las páginas/vistas principales. Las herramientas automáticas detectan ~30-40% de los problemas, pero son rápidas y escalables. Ideal como primera pasada antes del testing manual. Integrar en CI/CD para prevenir regresiones.", fix:"axe DevTools (extensión Chrome): análisis completo en 1 clic. Lighthouse CI en GitHub Actions: fallar build si score accesibilidad <90. IBM Equal Access: reglas adicionales no cubiertas por axe. Pa11y para testing headless automatizado." },
  { id:"PROC-06", area:"Proceso y QA", cat:"Documentación", item:"Hallazgos documentados con evidencia (capturas, criterio, URL)", tipo:"manual", wcag:"—", nivel:"—", tool:"Manual", team:"QA + Accesibilidad", sev:"medium", effort:"medium", who:"—", desc:"Cada hallazgo debe documentarse con: ID, criterio WCAG afectado, URL de la página, captura de pantalla (o del árbol de accesibilidad), severidad, impacto en usuarios, y recomendación de corrección con código de ejemplo. Sin documentación clara, los equipos de desarrollo no pueden priorizar ni corregir.", fix:"Plantilla por issue: 1) Criterio WCAG, 2) Severidad, 3) URL + paso para reproducir, 4) Captura + captura del accessibility tree, 5) Qué usuarios afecta, 6) Código actual vs código correcto. Agrupar por severidad en el informe final." },
  { id:"PROC-07", area:"Proceso y QA", cat:"Cultura", item:"El equipo ha recibido formación básica en accesibilidad", tipo:"manual", wcag:"—", nivel:"—", tool:"Assessment", team:"Todos los equipos", sev:"medium", effort:"high", who:"—", desc:"Sin formación básica en accesibilidad, los mismos errores se repetirán en cada nuevo desarrollo aunque se corrijan en auditoría. La formación debe cubrir: principios WCAG, testing con teclado, conceptos de SR, y errores comunes por rol (diseño, frontend, contenido).", fix:"Formación mínima por rol: Frontend (WCAG + ARIA + testing teclado, 1 día), Diseño (contraste + colores + tamaños, medio día), Contenido (alt + headings + lenguaje claro, medio día). Recursos gratuitos: w3.org/WAI/tips/, web.dev/learn/accessibility/" },
  { id:"PROC-08", area:"Proceso y QA", cat:"Monitoreo", item:"Existe mecanismo de feedback de accesibilidad para usuarios", tipo:"manual", wcag:"—", nivel:"—", tool:"Revisión UI", team:"UX + Frontend", sev:"medium", effort:"medium", who:"Usuarios con discapacidad", desc:"Debe existir un mecanismo visible (footer o página dedicada) para que los usuarios reporten barreras de accesibilidad. Obligatorio con la European Accessibility Act (EAA) desde junio 2025. Incluir: declaración de accesibilidad, nivel de conformidad, email/formulario de contacto, y plazo de respuesta.", fix:"En el footer: enlace 'Accesibilidad' a página con declaración de conformidad WCAG 2.2 AA, fecha de última auditoría, email de contacto para reportar problemas, y compromiso de plazo de respuesta (<5 días hábiles). Modelo de declaración: w3.org/WAI/planning/statements/" },
];
